mapper.update:
UPDATE esg.tb_approval_info AS tgt
SET signature = h.signature,
    updated_at = NOW(),
    updated_by = h.user_id
FROM esg.tb_toolboxmeeting AS t
JOIN esg.v_hr_info AS h
    ON t.write_year = #{writeYear}
    AND t.doc_type = #{docType}
    AND t.doc_no = #{docNo}
    AND t.use_yn = 'Y'
    AND h.hr_id = #{hrId}
    AND h.use_yn = 'Y'
WHERE tgt.target_type = t.doc_type
    AND tgt.target_id = t.write_year || t.doc_no
    AND tgt.hr_id = h.hr_id
    AND tgt.type = #{type}
;

UPDATE esg.tb_approval_info AS tgt
SET signature = null,
    updated_at = null,
    updated_by = null
FROM (
    SELECT
        t.doc_type AS target_type,
        t.write_year || t.doc_no AS target_id
    FROM esg.tb_toolboxmeeting AS t
    WHERE t.write_year = #{writeYear}
    AND t.doc_type = #{docType}
    AND t.doc_no = #{docNo}
    AND t.use_yn = 'Y'
) AS src
WHERE tgt.target_type = src.target_type
AND tgt.target_id = src.target_id
AND tgt.hr_id = #{hrId}
AND tgt.type = #{type}
;
